export function useAuthApi() {
    const { $api } = useNuxtApp()
    return {
        login(email: string, password: string) { return $api<any>('/auth/login', { method: 'POST', body: { email, password } }) },
        register(data: { fullName: string; email: string; password: string; phone?: string }) { return $api<any>('/auth/register', { method: 'POST', body: { ...data, userType: 'customer' } }) },
        logout() { return $api<any>('/auth/logout', { method: 'POST' }) },
        forgotPassword(email: string) { return $api<any>('/auth/forgot-password', { method: 'POST', body: { email } }) },
        resetPassword(token: string, newPassword: string) { return $api<any>('/auth/reset-password', { method: 'POST', body: { token, newPassword } }) },
    }
}
